head.script:
scwin.bizDivCntrYn = 0;
scwin.bizDivBulkYn = 1;

scwin.hid_odrKndCd = "";
scwin.hid_ctrtClntNo = "";
scwin.hid_ctrtNo = "";
scwin.hid_realMchtclntNo = "";
scwin.hid_chkUseFilter = "";
scwin.hid_chkReterieve = "";

scwin.YN_YES = 1;
scwin.YN_NO = 0;
scwin.TRANS_DEPARTMENT = "T";

scwin.v_row = 0;
scwin.v_colid = "";

scwin.loginLobranCd = "";

scwin.onpageload = function() {
    scwin.loginLobranCd = $c.ses.getLobranCd();
    scwin.f_defaultValue();
};

scwin.f_clearTabOrderInfo = function() {
    // TODO: parent.hid_odrNo 접근 - 부모 프레임 연동 필요
};

scwin.f_setTabOrderInfo = function(odrNo) {
    // TODO: parent.hid_odrNo 접근 - 부모 프레임 연동 필요
};

scwin.f_setDisplayOdrKndCd = function(odrKndCd) {
    switch (odrKndCd) {
        case "B1":
        case "B2":
        case "B3":
        case "B4":
            gr_odrWrkPathStpDetail.setColumnVisible("vsslCdPortcnt", false);
            break;
        default:
            gr_odrWrkPathStpDetail.setColumnVisible("vsslCdPortcnt", false);
            break;
    }
};

scwin.f_defaultValue = async function() {
    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableAllBtn();

    ds_orderSearch.set("odrNo", "");

    // TODO: lay_ctrtClntNm, lay_ctrtNo, lay_realMchtclntNm, lay_odrKndNm innerHTML 설정 - WebSquare textbox로 대체 필요

    scwin.hid_ctrtClntNo = "";
    scwin.hid_ctrtNo = "";
    scwin.hid_realMchtclntNo = "";

    ds_lobranQueryCondition.set("lobranCd", scwin.loginLobranCd);
    ds_lobranQueryCondition.set("lobranClsCd", "T");
    ds_lobranQueryCondition.set("deptmentCd", scwin.TRANS_DEPARTMENT);
    ds_lobranQueryCondition.set("useYn", scwin.YN_YES);

    await $c.sbm.execute(sbm_retrieveLobran);

    gr_odrCommWrkPath.setReadOnly("grid", false);
    scwin.hid_chkUseFilter = "true";

    scwin.f_clearTabOrderInfo();

    scwin.f_clearTabOrderInfo();

    ed_odrNo.setFocus();
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ed_odrNo]);
    if (chk) {
        let odrNo = ed_odrNo.getValue().replace(/\s*$/, '');

        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();
        $c.gus.cfEnableBtnOnly([btnSave]);

        ds_order.removeAll();
        ds_odrCommWrkPath.removeAll();
        ds_ctrtWrkPath.removeAll();
        ds_odrWrkPathStep.removeAll();
        ds_ctrtWrkPathStep.removeAll();

        ds_odrWrkPathStepDetail.removeAll();

        ds_orderSearch.set("odrNo", odrNo);
        await $c.sbm.execute(sbm_retrieve);
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(ed_odrNo);
    ed_odrNo.setFocus();
};

scwin.f_RetrieveWorkStep = async function() {
    if (ds_searchWrkStep.get("ctrtWrkPathSeq") == 0) {
        return;
    }
    await $c.sbm.execute(sbm_searchWorkStep);
};

scwin.f_InsertRow = async function() {
    let curRow = ds_odrWrkPathStepDetail.getRowPosition();
    if (ds_odrWrkPathStepDetail.getCellData(curRow, "odrWrkStpSeq") % 10 < 9) {
        ds_odrWrkPathStepDetail.insertRow(curRow + 1);
        scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, curRow, curRow + 1);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["작업단계"]);
        return;
    }
};

scwin.f_AddRow = function() {
    let lastRow = ds_odrWrkPathStepDetail.getRowCount() - 1;
    ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowCount());
    scwin.f_CopyDataRow(ds_odrWrkPathStepDetail, lastRow, ds_odrWrkPathStepDetail.getRowCount() - 1);
};

scwin.f_CopyDataRow = function(dataObject, sourceRow, targetRow) {
    let v_odrWrkStpSeq = dataObject.getCellData(sourceRow, "odrWrkStpSeq");
    let v_tempSeq = parseInt(parseInt(v_odrWrkStpSeq) / 10) * 10;
    let colCount = dataObject.getColumnCount();

    for (let i = 0; i < colCount; i++) {
        let colId = dataObject.getColumnID(i);
        if (colId == "odrWrkStpSeq") {
            dataObject.setCellData(targetRow, colId, parseInt(dataObject.getCellData(sourceRow, colId)) + 1);
        } else {
            dataObject.setCellData(targetRow, colId, dataObject.getCellData(sourceRow, colId));
        }
    }

    for (let j = 0; j < dataObject.getRowCount(); j++) {
        let v_compSeq = parseInt(dataObject.getCellData(j, "odrWrkStpSeq")) - v_tempSeq;
        if (parseInt(dataObject.getCellData(j, "odrWrkStpSeq")) > v_tempSeq && v_compSeq > 0 && v_compSeq < 10) {
            if (j > 0) {
                dataObject.setCellData(j, "odrWrkStpSeq", parseInt(dataObject.getCellData(j - 1, "odrWrkStpSeq")) + 1);
            }
        }
    }
};

scwin.f_Update = function() {
    $c.gus.cfDisableBtnOnly([btnUpdate]);
    $c.gus.cfEnableBtnOnly([btnSave]);

    gr_odrCommWrkPath.setReadOnly("grid", false);
    gr_odrWrkPathStpDetail.setReadOnly("grid", false);

    if (ds_odrWrkPathStep.getRowCount() > 0) {
        gr_odrWrkPathStpDetail.setColumnReadOnly("wrkPlClsCd", true);
        gr_odrWrkPathStpDetail.setColumnReadOnly("wrkStpCd", true);
        gr_odrWrkPathStpDetail.setColumnReadOnly("selpchItemNm", true);
        gr_odrWrkPathStpDetail.setColumnReadOnly("dptWrkPlNm", true);
    }

    gr_odrWrkPathStpDetail.setFocusedCell(ds_odrWrkPathStepDetail.getRowPosition(), "wrkLobranNm");
    scwin.v_row = ds_odrWrkPathStepDetail.getRowPosition();
    scwin.v_colid = "wrkLobranNm";

    let odrCommWrkPathRow = ds_odrCommWrkPath.getRowPosition();
    if (odrCommWrkPathRow >= 0 && btnUpdate.getDisabled()) {
        if (scwin.f_chkResultsConfirmationCommodity(odrCommWrkPathRow)) {
            gr_odrCommWrkPath.setReadOnly("grid", true);
            gr_odrWrkPathStpDetail.setReadOnly("grid", true);
        } else {
            gr_odrCommWrkPath.setReadOnly("grid", false);
            gr_odrWrkPathStpDetail.setReadOnly("grid", false);
        }
    }
};

scwin.f_Save = async function() {
    if (parseInt(ds_odrCommWrkPath.getCellData(0, "ctrtWrkPathSeq")) <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업경로"]);
        gr_odrCommWrkPath.setFocusedCell(0, "ctrtWrkPathSeq");
        return;
    }

    for (let i = 0; i < ds_odrWrkPathStepDetail.getRowCount(); i++) {
        if (ds_odrWrkPathStepDetail.getCellData(i, "wrkPlClsCd").trim() == "" && i > 0) {
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkLobranCd")) && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != "0000")
                ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkLobranCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "wrkLobranNm")) && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != "0000")
                ds_odrWrkPathStepDetail.setCellData(i, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "wrkLobranNm"));

            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "dptWrkPlCd")))
                ds_odrWrkPathStepDetail.setCellData(i, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "dptWrkPlCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "arvWrkPlCd")) && (i + 1) < ds_odrWrkPathStepDetail.getRowCount())
                ds_odrWrkPathStepDetail.setCellData(i, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(i + 1, "dptWrkPlNm"));

            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "internalSellLodeptCd")) && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != "0000")
                ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptCd"));
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i, "internalSellLodeptNm")) && ds_odrWrkPathStepDetail.getCellData(i, "selpchItemCd") != "0000" && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptNm")))
                ds_odrWrkPathStepDetail.setCellData(i, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(i - 1, "internalSellLodeptNm"));
        }
    }

    let chkGrid = await $c.gus.cfValidate([gr_odrWrkPathStpDetail]);
    if (!chkGrid) {
        return;
    }

    for (let idx = 0; idx < ds_odrWrkPathStepDetail.getRowCount(); idx++) {
        if (!$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkPlClsCd").trim()) && $c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "dptWrkPlCd").trim())) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업장"]);
            gr_odrWrkPathStpDetail.setFocusedCell(idx, "dptWrkPlNm");
            return false;
        }

        if (ds_odrWrkPathStepDetail.getCellData(idx, "selpchItemCd") != "0000") {
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "wrkLobranCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업점소"]);
                gr_odrWrkPathStpDetail.setFocusedCell(idx, "wrkLobranNm");
                return false;
            }
            if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(idx, "internalSellLodeptCd").trim())) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["매출귀속부서"]);
                gr_odrWrkPathStpDetail.setFocusedCell(idx, "internalSellLodeptNm");
                return false;
            }
        }
    }

    ds_odrCommWrkPath.setRowPosition(0);

    let chkGrid2 = await $c.gus.cfValidate([gr_odrWrkPathStpDetail]);
    if (!chkGrid2) {
        return;
    }

    $c.gus.cfShowDSWaitMsg(gr_odrWrkPathStpDetail);

    scwin.hid_chkUseFilter = "false";

    let v_wrkPathRows = ds_odrCommWrkPath.getRowCount();
    let v_wrkPathStepRows = ds_odrWrkPathStepDetail.getRowCount();

    let v_odrNo = ds_odrCommWrkPath.getCellData(0, "odrNo");
    let v_commSeq = ds_odrCommWrkPath.getCellData(0, "commSeq");

    for (let i = 0; i < v_wrkPathRows; i++) {
        if (i == 0) {
            for (let j = ds_odrWrkPathStepDetail.getRowCount() - 1; j >= 0; j--) {
                if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo") &&
                    ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq") &&
                    ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") != ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq") && ds_odrWrkPathStepDetail.getRowStatus(j) != "U") {
                    ds_odrWrkPathStepDetail.removeRow(j);
                }
            }
        }

        if (parseInt(ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq")) <= 0 && i > 0) {
            ds_odrCommWrkPath.setCellData(i, "ctrtWrkPathSeq", ds_odrCommWrkPath.getCellData(0, "ctrtWrkPathSeq"));

            for (let j = ds_odrWrkPathStepDetail.getRowCount() - 1; j >= 0; j--) {
                if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo") &&
                    ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq") &&
                    ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") == ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq") && ds_odrWrkPathStepDetail.getRowStatus(j) != "U") {
                    ds_odrWrkPathStepDetail.removeRow(j);
                } else if (ds_odrWrkPathStepDetail.getCellData(j, "odrNo") == ds_odrCommWrkPath.getCellData(i, "odrNo") &&
                    ds_odrWrkPathStepDetail.getCellData(j, "commSeq") == ds_odrCommWrkPath.getCellData(i, "commSeq") &&
                    ds_odrWrkPathStepDetail.getCellData(j, "ctrtWrkPathSeq") != ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq") && ds_odrWrkPathStepDetail.getRowStatus(j) != "U") {
                    ds_odrWrkPathStepDetail.removeRow(j);
                }
            }

            for (let j = 0; j < v_wrkPathStepRows; j++) {
                if (ds_odrWrkPathStepDetail.getRowStatus(j) != "D"
                    && v_odrNo == ds_odrWrkPathStepDetail.getCellData(j, "odrNo")
                    && v_commSeq == ds_odrWrkPathStepDetail.getCellData(j, "commSeq")) {

                    let newRow = ds_odrWrkPathStepDetail.insertRow(ds_odrWrkPathStepDetail.getRowCount());
                    let colCount = ds_odrWrkPathStepDetail.getColumnCount();
                    for (let k = 0; k < colCount; k++) {
                        let colId = ds_odrWrkPathStepDetail.getColumnID(k);
                        switch (colId) {
                            case "commSeq":
                                ds_odrWrkPathStepDetail.setCellData(newRow, colId, ds_odrCommWrkPath.getCellData(i, "commSeq"));
                                break;
                            case "odrWrkPathSeq":
                                ds_odrWrkPathStepDetail.setCellData(newRow, colId, ds_odrCommWrkPath.getCellData(i, "odrWrkPathSeq"));
                                break;
                            case "ctrtWrkPathSeq":
                                ds_odrWrkPathStepDetail.setCellData(newRow, colId, ds_odrCommWrkPath.getCellData(i, "ctrtWrkPathSeq"));
                                break;
                            default:
                                ds_odrWrkPathStepDetail.setCellData(newRow, colId, ds_odrWrkPathStepDetail.getCellData(j, colId));
                                break;
                        }
                    }
                    scwin.f_setCtrtWrkPathStepToWrkPathStepDetail_1(i);
                }
            }
        }
    }

    for (let j = 0; j < ds_odrWrkPathStepDetail.getRowCount(); j++) {
        if (ds_odrWrkPathStepDetail.getCellData(j, "wrkPlClsCd").trim() == "") {
            if (j > 0 && j < ds_odrWrkPathStepDetail.getRowCount() - 1) {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000")
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranCd"));
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000")
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranNm"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd").trim()))
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd").trim()) && (j + 1) < ds_odrWrkPathStepDetail.getRowCount())
                    ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000") {
                    if ((j + 1) < ds_odrWrkPathStepDetail.getRowCount() && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptCd").trim()))
                        ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptCd"));
                }
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000") {
                    if ((j + 1) < ds_odrWrkPathStepDetail.getRowCount() && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm").trim()))
                        ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm"));
                }
            } else if (j == 0) {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000" && (j + 1) < ds_odrWrkPathStepDetail.getRowCount())
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkLobranCd"));
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000" && (j + 1) < ds_odrWrkPathStepDetail.getRowCount())
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "wrkLobranNm"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "arvWrkPlCd").trim()) && (j + 1) < ds_odrWrkPathStepDetail.getRowCount())
                    ds_odrWrkPathStepDetail.setCellData(j, "arvWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "dptWrkPlCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000" && (j + 1) < ds_odrWrkPathStepDetail.getRowCount())
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptCd"));
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000" && (j + 1) < ds_odrWrkPathStepDetail.getRowCount() && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm")))
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(j + 1, "internalSellLodeptNm"));
            } else {
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000")
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranCd"));
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "wrkLobranNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000")
                    ds_odrWrkPathStepDetail.setCellData(j, "wrkLobranNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "wrkLobranNm"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "dptWrkPlCd").trim()))
                    ds_odrWrkPathStepDetail.setCellData(j, "dptWrkPlCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "dptWrkPlCd"));

                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptCd").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000")
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptCd", ds_odrWrkPathStepDetail.getCellData(j - 1, "internalSellLodeptCd"));
                if ($c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j, "internalSellLodeptNm").trim()) && ds_odrWrkPathStepDetail.getCellData(j, "selpchItemCd") != "0000" && !$c.gus.cfIsNull(ds_odrWrkPathStepDetail.getCellData(j - 1, "internalSellLodeptNm")))
                    ds_odrWrkPathStepDetail.setCellData(j, "internalSellLodeptNm", ds_odrWrkPathStepDetail.getCellData(j - 1, "internalSellLodeptNm"));
            }
        }
    }

    scwin.hid_chkUseFilter = "true";

    if (scwin.f_validChk()) {
        scwin.f_chkOdrWrkPathStep();

        let confirmResult = await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_001, ["작업단계정보"]));
        if (confirmResult) {
            await $c.sbm.execute(sbm_save);
        } else {
            $c.gus.cfHideDSWaitMsg(gr_odrWrkPathStpDetail);
        }
    } else {
        $c.gus.cfHideDSWaitMsg(gr_odrWrkPathStpDetail);
    }
};

scwin.f_validChk = async function() {
    let chk = await $c.gus.cfValidate([gr_odrCommWrkPath, gr_odrWrkPathStpDetail]);
    if (chk) {
        for (let idx = 0; idx < ds_odrCommWrkPath.getRowCount(); idx++) {
            if (parseInt(ds_odrCommWrkPath.getCellData(idx, "ctrtWrkPathSeq")) <= 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["작업경로"]);
                return false;
            }
        }
        return true;
    } else {
        return false;
    }
};

scwin.f_openCommPopUpGrid = function(disGubun, row, pCode, pName, pClose, pAllSearch) {
    let rtnList = null;
    let chkValue = false;

    switch (disGubun) {
        case 1:
