        let param = {
            odrNo: v_odrNo,
            type: "retrieve"
        };
        // TODO: parent.f_TabMenuUpdate 호출 - 부모 프레임 연동 필요
        $c.win.openMenu("작업일시배분조회및수정", "/ui/ds/sd/odrmgnt/tplreg/sd_402_01_14b.xml", "sd_402_01_14b.xml", param);
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["작업단계"]);
        return;
    }
};

scwin.f_chkResultsConfirmationCommodity = function(row) {
    if (row >= 0) {
        if (!$c.gus.cfIsNull(ds_odrCommWrkPath.getCellData(row, "wrkRsltsNo").trim())) {
